params.script:
// 予約日（変更）が当日かどうかを判定する
// 入力: OpenAI_予約日_変更 の出力（yyyy-MM-dd 00:00:00 または NO_RESULT）
// 出力: 当日（予約日 = 今日）/ "" (default: 今日以外)
var input = $runner.getModuleResult("OpenAI_予約日_変更");
var res = "";

if (input) {
    var inputStr = input.toString().trim();
    var reservationDate = "";

    // yyyy-MM-dd HH:mm:ss 形式 → 先頭10文字（yyyy-MM-dd）のみ取得
    if (inputStr.length >= 10 && inputStr !== "NO_RESULT") {
        reservationDate = inputStr.substring(0, 10);
    }

    // 現在日付を yyyy-MM-dd 形式で取得
    var now = new Date();
    var year = now.getFullYear();
    var month = ("0" + (now.getMonth() + 1)).slice(-2);
    var day = ("0" + now.getDate()).slice(-2);
    var todayDate = year + "-" + month + "-" + day;

    // 予約日 = 今日なら「当日」
    if (reservationDate === todayDate) {
        res = "当日";
    }
}

$runner.setResult(res);

// 予約日（キャンセル）が当日かどうかを判定する
// 入力: OpenAI_予約日_キャンセル の出力（yyyy-MM-dd 00:00:00 または NO_RESULT）
// 出力: 当日（予約日 = 今日）/ "" (default: 今日以外)
var input = $runner.getModuleResult("OpenAI_予約日_キャンセル");
var res = "";

if (input) {
    var inputStr = input.toString().trim();
    var reservationDate = "";

    // yyyy-MM-dd HH:mm:ss 形式 → 先頭10文字（yyyy-MM-dd）のみ取得
    if (inputStr.length >= 10 && inputStr !== "NO_RESULT") {
        reservationDate = inputStr.substring(0, 10);
    }

    // 現在日付を yyyy-MM-dd 形式で取得
    var now = new Date();
    var year = now.getFullYear();
    var month = ("0" + (now.getMonth() + 1)).slice(-2);
    var day = ("0" + now.getDate()).slice(-2);
    var todayDate = year + "-" + month + "-" + day;

    // 予約日 = 今日なら「当日」
    if (reservationDate === todayDate) {
        res = "当日";
    }
}

$runner.setResult(res);
